const rows = items.map(i => i.json);
if (!rows || rows.length === 0) {
  return [{ json: { erreur: "Aucune donnée reçue." } }];
}

// ── Filtrer les lignes vides (;;;;) ───────────────────────────────
const rowsFiltres = rows.filter(row => {
  const valeurs = Object.values(row);
  return valeurs.some(v => v !== "" && v !== null && v !== undefined);
});

if (rowsFiltres.length === 0) {
  return [{ json: { erreur: "Aucune donnée valide après filtrage." } }];
}

const CODE_FRAIS_EQUIPEMENT = {
  "70600100":  "46783000",
  "70600600":  "46782010",
  "70600300":  "46781000",
  "70600200":  "46784000",
  "70600500":  "46786200",
  "706001200": "46786300",
};

const FOURNISSEUR_VERS_COMPTE = {
  "411AKTO":     "70600100",
  "411OCAPIAT":  "70600500",
  "411OPCOMOBI": "706001200",
  "411AFDAS":    "70600600",
  "411OPCOMMER": "70600300",
  "411OPCOEP":   "70600200",
};

const COL = {
  JOURNAL:   "@JOURNAL",
  NUM_PIECE: "Numéro de pièce",
  ETAB_JJ: "Etab-JJ", ETAB_MM: "Etab-MM", ETAB_AAAA: "Etab-AAAA",
  ECH_JJ:  "Ech-JJ",  ECH_MM:  "Ech-MM",  ECH_AAAA:  "Ech-AAAA",
  COMPTE:   "Compte Imputé",
  DEBIT:    "Débit",
  CREDIT:   "Crédit",
  INTITULE: "Intitulé Ecriture Tiers",
  SESSION:  "Session",
};

function recomposerDate(j, m, a) {
  if (!j || !m || !a) return "";
  return `${String(j).padStart(2,"0")}/${String(m).padStart(2,"0")}/${a}`;
}

function nettoyerPiece(val) {
  return String(val ?? "")
    .replace(/^FCT-/, "")
    .replace(/-CFAMED/g, "");
}

function toNum(val) {
  return parseFloat(String(val ?? "0").replace(",", ".")) || 0;
}

// ── Boucle principale ──────────────────────────────────────────────
const resultat = [];
let numeroMouvement = 0;
let dernierNumPiece = null;

for (let i = 0; i < rowsFiltres.length; i++) {
  const row       = rowsFiltres[i];
  const numPiece  = nettoyerPiece(row[COL.NUM_PIECE]);
  const debitNum  = toNum(row[COL.DEBIT]);
  const creditNum = toNum(row[COL.CREDIT]);
  const estPremier = i === 0 || nettoyerPiece(rowsFiltres[i-1][COL.NUM_PIECE]) !== numPiece;
  const estAvoir   = numPiece.startsWith("AV-");

  if (numPiece !== dernierNumPiece) { numeroMouvement++; dernierNumPiece = numPiece; }

  let codePaiement = "";
  if (estAvoir) {
    // Avoir : uniquement VIR sur la 1ère ligne crédit, rien d'autre
    if (estPremier && creditNum > 0) codePaiement = "VIR";
  } else {
    // Facture normale : VIR sur 1ère ligne débit, APP sur 1ère ligne crédit
    if (estPremier && debitNum > 0)       codePaiement = "VIR";
    else if (estPremier && creditNum > 0) codePaiement = "APP";
  }

  resultat.push({
    "@JOURNAL":                row[COL.JOURNAL]  ?? "",
    "Numéro de pièce":         numPiece,
    "Date etab":               recomposerDate(row[COL.ETAB_JJ], row[COL.ETAB_MM], row[COL.ETAB_AAAA]),
    "Date ech":                recomposerDate(row[COL.ECH_JJ],  row[COL.ECH_MM],  row[COL.ECH_AAAA]),
    "Compte Imputé":           String(row[COL.COMPTE] ?? "").trim(),
    "Débit":                   row[COL.DEBIT]    ?? "",
    "Crédit":                  row[COL.CREDIT]   ?? "",
    "Intitulé Ecriture Tiers": row[COL.INTITULE] ?? "",
    "Session":                 row[COL.SESSION]  ?? "",
    "Code de paiement":        codePaiement,
    "Numéro de mouvement":     numeroMouvement,
  });
}

// ── Traitement des comptes par facture ─────────────────────────────
const pieces = [...new Set(resultat.map(r => r["Numéro de pièce"]))];

for (const piece of pieces) {
  const lignes = resultat.filter(r => r["Numéro de pièce"] === piece);
  const estAvoir = piece.startsWith("AV-");

  let compteRef = "";
  if (estAvoir) {
    const ligneCredit = lignes.find(r => toNum(r["Crédit"]) > 0);
    compteRef = ligneCredit?.["Compte Imputé"] ?? "";
  } else {
    const ligneDebit = lignes.find(r => toNum(r["Débit"]) > 0);
    compteRef = ligneDebit?.["Compte Imputé"] ?? "";
  }

  const compteSource = FOURNISSEUR_VERS_COMPTE[compteRef] ?? compteRef;

  for (const ligne of lignes) {
    const d = toNum(ligne["Débit"]);
    const c = toNum(ligne["Crédit"]);
    const compte = ligne["Compte Imputé"];

    if (estAvoir && c > 0) continue;
    if (!estAvoir && d > 0) continue;

    if (c === 500 || d === 500) {
      ligne["Compte Imputé"] = CODE_FRAIS_EQUIPEMENT[compteSource] ?? "";
      continue;
    }

    if (!compte || FOURNISSEUR_VERS_COMPTE[compte]) {
      ligne["Compte Imputé"] = compteSource;
    }
  }
}

// ── Retour des lignes uniquement ───────────────────────────────────
return resultat.map(ligne => ({ json: ligne }));

const lignes = $input.first().json.lignes;

const lignesFiltrees = lignes.map(l => ({
  "num":          l["Numéro de pièce"],
  "date_etab":    l["Date etab"],
  "date_ech":     l["Date ech"],
  "compte":       l["Compte Imputé"],
  "debit":        l["Débit"],
  "credit":       l["Crédit"],
  "code_paiement":l["Code de paiement"],
  "mouvement":    l["Numéro de mouvement"]
}));

return [{ json: { lignes: lignesFiltrees } }];
